\begin{tikzpicture}[scale=0.85]
\path[use as bounding box] (-0.8,-1.8) rectangle (7.2,2.2);
\draw[->, gray!50] (-0.5,0) -- (7,0) node[below right, text=white, font=\scriptsize] {$x$};
\draw[->, gray!50] (0,-1.5) -- (0,1.9) node[left, text=white, font=\scriptsize] {$\psi(x)$};
\draw[thick, cyan!70, domain=-0.3:6.8, samples=200] plot (\x, {1.2*exp(-(\x-3)*(\x-3)/1.5)*cos(deg(4*\x))});
\draw[thick, violet!60, domain=0.3:5.7, dashed] plot (\x, {1.2*exp(-(\x-3)*(\x-3)/1.5)});
\draw[thick, violet!60, domain=0.3:5.7, dashed] plot (\x, {-1.2*exp(-(\x-3)*(\x-3)/1.5)});
\draw[violet!70, <->, thick] (1.5, -1.35) -- (4.5, -1.35) node[midway, below, text=white, font=\scriptsize] {$\Delta x$};
\node[text=cyan!70, font=\scriptsize] at (5.9, -0.8) {wave packet};
\node[text=violet!60, font=\scriptsize, anchor=west] at (5.0, 1.0) {envelope};
\end{tikzpicture}
